const msg = $input.first().json.message;
const userId = msg.from.id;
const chatId = msg.chat.id;
const userMessage = msg.text || '';
const userName = msg.from.first_name || msg.from.username || 'User';
const userMessageType = msg.entities && msg.entities.length > 0 ? msg.entities[0].type : '';

return [{
  json: {
    userId,
    chatId,
    userMessage,
    userName,
    userMessageType,
    messageId: msg.message_id
  }
}];

const lockResult = $input.first().json;
const initData = $('Init Data').first().json;

return [{
  json: {
    ...initData,
    isLocked: lockResult.was_locked === true,
    lockInfo: lockResult
  }
}];

