const agentOutput = $input.first().json;
const response = agentOutput.output || agentOutput.text || 'Извини, произошла ошибка. Попробуй ещё раз.';

// Обрезаем до лимита Telegram (4096 символов)
const trimmed = response.length > 4096 ? response.substring(0, 4093) + '...' : response;

return [{
  json: {
    response: trimmed,
    userId: $('Init Data').first().json.userId,
    chatId: $('Init Data').first().json.chatId,
    messageId: $('Init Data').first().json.messageId
  }
}];

const error = $input.first().json;
// Используем Format Lock Result, так как он содержит все данные из Init Data
let lockData;
try {
  lockData = $('Format Lock Result').first().json;
} catch (e) {
  // Fallback на Init Data если Format Lock Result недоступен
  lockData = $('Init Data').first().json;
}

return [{
  json: {
    chatId: lockData.chatId || error.chatId || 0,
    userId: lockData.userId || error.userId || 0,
    messageId: lockData.messageId || error.messageId,
    errorMessage: '😔 Упс, у меня что-то сломалось...\n\nПопробуй написать ещё раз через минуту.\n\nЕсли проблема повторяется — напиши @pandanax',
    errorDetails: JSON.stringify(error, null, 2)
  }
}];
